# Secure version
from flask import Flask, request, jsonify
from sklearn.feature_extraction.text import CountVectorizer
from sklearn.linear_model import LogisticRegression
from sklearn.pipeline import make_pipeline
import numpy as np
import joblib
import re

# Sample training data
emails = [
    "Congratulations! You've won a lottery.",
    "Dear friend, I need your help with a business proposal.",
    "This is a reminder for your appointment tomorrow.",
    "Get paid to work from home!",
    "Your invoice is attached.",
    "Click here to claim your prize."
]
labels = [1, 1, 0, 1, 0, 1]  # 1 for spam, 0 for not spam

# Create a pipeline with CountVectorizer and LogisticRegression
model = make_pipeline(CountVectorizer(), LogisticRegression())
model.fit(emails, labels)

# Save the model
joblib.dump(model, 'spam_detector.pkl')

# Load the model
model = joblib.load('spam_detector.pkl')

app = Flask(__name__)

def sanitize_input(text):
    return re.sub(r'[^a-zA-Z0-9\s]', '', text)

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json
    email_text = data.get('email_text', '')
    
    if not email_text:
        return jsonify({'error': 'No email text provided'}), 400
    
    # Sanitize input
    email_text = sanitize_input(email_text)
    
    # Predict spam probability
    spam_prob = model.predict_proba([email_text])[0][1]
    return jsonify({'spam_probability': spam_prob})

if __name__ == '__main__':
    app.run(debug=True)